const cp = require('child_process');
const scanDir = '__DOCUMENTS_DIR__';
const projRoot = '__PROJECT_ROOT__';

try {
  const raw = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const agentProjects = raw.trim().split('\n').filter(l => l.includes('|true|')).map(l => l.split('|')[0]);
  const alerts = [];
  for (const name of agentProjects) {
    const path = scanDir + '/' + name;
    try {
      const output = cp.execSync('bash scripts/check-drift.sh 2>&1', {cwd: path, timeout: 30000, encoding: 'utf8'});
      const w = parseInt((output.match(/(\d+) warnings/) || [,'0'])[1]);
      const e = parseInt((output.match(/(\d+) errors/) || [,'0'])[1]);
      if (w > 0 || e > 0) alerts.push({project: name, warnings: w, errors: e});
    } catch { alerts.push({project: name, warnings: 0, errors: 1, error: 'check-drift failed'}); }
  }
  return [{json: {status:'complete', total_alerts:alerts.length, message:alerts.length===0?'All projects healthy':alerts.length+' project(s) need attention', alerts, timestamp:new Date().toISOString()}}];
} catch(e) {
  return [{json: {status:'error', error:(e.stderr||'')+e.message}}];
}
